<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Facades\Validator;

class LinkPreviewController extends Controller
{
    public function show(Request $request)
    {
        $validated = Validator::make($request->all(), [
            'url' => ['required', 'string'],
        ])->validate();

        $url = trim($validated['url']);

        if (!filter_var($url, FILTER_VALIDATE_URL)) {
            return response()->json([
                'message' => 'Invalid URL provided.',
            ], 422);
        }

        $cacheKey = 'link_preview:' . sha1($url);

        $preview = Cache::remember($cacheKey, now()->addMinutes(15), function () use ($url) {
            return $this->fetchPreview($url);
        });

        if (!$preview) {
            return response()->json([
                'message' => 'Unable to fetch preview for the provided URL.',
            ], 422);
        }

        return response()->json($preview);
    }

    protected function fetchPreview(string $url): ?array
    {
        $ch = curl_init();

        curl_setopt_array($ch, [
            CURLOPT_URL => $url,
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_FOLLOWLOCATION => true,
            CURLOPT_MAXREDIRS => 5,
            CURLOPT_CONNECTTIMEOUT => 10,
            CURLOPT_TIMEOUT => 20,
            CURLOPT_USERAGENT => 'Mozilla/5.0 (compatible; LinkPreviewBot/1.0)',
            CURLOPT_SSL_VERIFYPEER => true,
            CURLOPT_SSL_VERIFYHOST => 2,
            CURLOPT_HEADER => false,
        ]);

        $html = curl_exec($ch);
        $curlError = curl_error($ch);
        $httpCode = (int) curl_getinfo($ch, CURLINFO_HTTP_CODE);

        curl_close($ch);

        if ($html === false || $curlError || $httpCode < 200 || $httpCode >= 400) {
            return null;
        }

        libxml_use_internal_errors(true);

        $dom = new \DOMDocument();
        @$dom->loadHTML($html);

        $meta = $this->extractMetaTags($dom);

        $title = $meta['title'] ?? $this->getTitleFromDom($dom);
        $description = $meta['description'] ?? null;
        $image = $meta['image'] ?? null;
        $siteName = $meta['site_name'] ?? null;

        return [
            'url' => $url,
            'title' => $title,
            'description' => $description,
            'image' => $image,
            'site_name' => $siteName,
            'favicon' => $this->guessFaviconUrl($url),
        ];
    }

    protected function extractMetaTags(\DOMDocument $dom): array
    {
        $result = [];

        foreach ($dom->getElementsByTagName('meta') as $meta) {
            $property = $meta->getAttribute('property');
            $name = $meta->getAttribute('name');
            $content = $meta->getAttribute('content');

            if (!$content) {
                continue;
            }

            switch (true) {
                case $property === 'og:title':
                    $result['title'] = $content;
                    break;
                case $property === 'og:description':
                    $result['description'] = $content;
                    break;
                case $property === 'og:image':
                    $result['image'] = $content;
                    break;
                case $property === 'og:site_name':
                    $result['site_name'] = $content;
                    break;
                case $name === 'description' && !isset($result['description']):
                    $result['description'] = $content;
                    break;
            }
        }

        foreach ($dom->getElementsByTagName('title') as $titleTag) {
            $result['title'] = trim($titleTag->textContent);
            break;
        }

        return $result;
    }

    protected function getTitleFromDom(\DOMDocument $dom): ?string
    {
        foreach ($dom->getElementsByTagName('title') as $titleTag) {
            $title = trim($titleTag->textContent);
            return $title !== '' ? $title : null;
        }

        return null;
    }

    protected function guessFaviconUrl(string $url): ?string
    {
        $parts = parse_url($url);

        if (!isset($parts['scheme'], $parts['host'])) {
            return null;
        }

        return $parts['scheme'] . '://' . $parts['host'] . '/favicon.ico';
    }
}